// src/components/ParticlesBg.jsx
import { useEffect, useRef } from 'react';

export default function ParticlesBg() {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    let animId;

    let width = canvas.offsetWidth;
    let height = canvas.offsetHeight;

    const resize = () => {
      width = canvas.parentElement.offsetWidth;
      height = canvas.parentElement.offsetHeight;
      canvas.width = width;
      canvas.height = height;
    };
    resize();

    const ro = new ResizeObserver(resize);
    if (canvas.parentElement) ro.observe(canvas.parentElement);

    // --- MAGIA RESPONSIVE ---
    // Detectamos si es móvil para reducir el "ruido" visual
    const isMobile = width < 850;
    
    // 180 en PC (épico), 60 en móvil (elegante y limpio)
    const PARTICLE_COUNT = isMobile ? 60 : 180; 
    
    // Radio del imán más pequeño en móvil
    let mouse = { x: null, y: null, active: false, radius: isMobile ? 120 : 220 };

    const onMove = (e) => {
      // Soporte tanto para ratón de PC como para dedo en móvil
      const clientX = e.touches ? e.touches[0].clientX : e.clientX;
      const clientY = e.touches ? e.touches[0].clientY : e.clientY;
      
      const rect = canvas.getBoundingClientRect();
      mouse.x = clientX - rect.left;
      mouse.y = clientY - rect.top;
      mouse.active = true;
    };
    
    const onLeave = () => { mouse.active = false; };

    if (canvas.parentElement) {
      canvas.parentElement.addEventListener('mousemove', onMove);
      canvas.parentElement.addEventListener('mouseleave', onLeave);
      // Eventos táctiles para móvil
      canvas.parentElement.addEventListener('touchmove', onMove, { passive: true });
      canvas.parentElement.addEventListener('touchend', onLeave);
    }

    const particles = Array.from({ length: PARTICLE_COUNT }, () => {
      const angle = Math.random() * Math.PI * 2;
      // En móvil se mueven un pelín más lento para dar paz visual
      const speed = Math.random() * (isMobile ? 0.5 : 0.8) + 0.2; 
      return {
        x: Math.random() * width,
        y: Math.random() * height,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        r: Math.random() * 1.5 + 0.5,
        alpha: Math.random() * 0.4 + 0.2,
        phase: Math.random() * 100, 
        speedPhase: Math.random() * 0.02 + 0.005,
      };
    });

    const draw = () => {
      // En móvil borramos la estela un poco más rápido (0.1 en vez de 0.06) 
      // para que el fondo se vea más negro y el texto se lea mejor
      ctx.fillStyle = isMobile ? 'rgba(10, 10, 12, 0.1)' : 'rgba(10, 10, 12, 0.06)'; 
      ctx.fillRect(0, 0, width, height);

      particles.forEach(p => {
        p.phase += p.speedPhase;

        let ax = Math.sin(p.phase + p.y * 0.005) * 0.12;
        let ay = Math.cos(p.phase + p.x * 0.005) * 0.12;

        if (mouse.active && mouse.x !== null && mouse.y !== null) {
          const dx = mouse.x - p.x;
          const dy = mouse.y - p.y;
          const dist = Math.sqrt(dx * dx + dy * dy);

          if (dist < mouse.radius) {
            const force = (mouse.radius - dist) / mouse.radius;
            
            const pullX = (dx / dist) * force * 0.4;
            const pullY = (dy / dist) * force * 0.4;

            // En móvil el torbellino es menos violento para que al hacer scroll no se vuelva loco
            const tangentForce = isMobile ? 1.0 : 1.8;
            const tangentX = (-dy / dist) * force * tangentForce;
            const tangentY = (dx / dist) * force * tangentForce;

            ax += pullX + tangentX;
            ay += pullY + tangentY;
          }
        }

        p.vx += ax;
        p.vy += ay;
        p.vx *= 0.96;
        p.vy *= 0.96;

        p.x += p.vx;
        p.y += p.vy;

        if (p.x < -20) p.x = width + 20;
        if (p.x > width + 20) p.x = -20;
        if (p.y < -20) p.y = height + 20;
        if (p.y > width + 20) p.y = -20;

        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);

        let finalAlpha = p.alpha;
        let finalColor = `rgba(232, 58, 58, ${finalAlpha})`;

        if (mouse.active && mouse.x !== null && mouse.y !== null) {
          const dx = mouse.x - p.x;
          const dy = mouse.y - p.y;
          const dist = Math.sqrt(dx * dx + dy * dy);
          if (dist < mouse.radius) {
            const factor = (mouse.radius - dist) / mouse.radius;
            finalAlpha = p.alpha + factor * 0.6;
            finalColor = `rgba(${232 + Math.floor(factor * 23)}, ${58 + Math.floor(factor * 40)}, 58, ${finalAlpha})`;
          }
        }

        ctx.fillStyle = finalColor;
        ctx.fill();
      });

      animId = requestAnimationFrame(draw);
    };

    draw();

    return () => {
      cancelAnimationFrame(animId);
      ro.disconnect();
      if (canvas.parentElement) {
        canvas.parentElement.removeEventListener('mousemove', onMove);
        canvas.parentElement.removeEventListener('mouseleave', onLeave);
        canvas.parentElement.removeEventListener('touchmove', onMove);
        canvas.parentElement.removeEventListener('touchend', onLeave);
      }
    };
  }, []);

  return (
    <canvas
      ref={canvasRef}
      style={{
        position: 'absolute',
        inset: 0,
        width: '100%',
        height: '100%',
        zIndex: 0,
        pointerEvents: 'none',
      }}
    />
  );
}
